import axios from 'axios';

const API = axios.create({
    baseURL: process.env.REACT_APP_API_URL || 'http://localhost:5000/api',
    headers: {
        'Content-Type': 'application/json',
    },
});


// Request interceptor to add token
API.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        console.log('API Request:', {
            url: config.url,
            method: config.method,
            data: config.data,
            hasToken: !!token
        });

        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        } else {
            console.warn('No token found in localStorage');
        }
        return config;
    },
    (error) => {
        console.error('Request interceptor error:', error);
        return Promise.reject(error);
    }
);

// Response interceptor to handle errors
API.interceptors.response.use(
    (response) => {
        console.log('API Response Success:', {
            url: response.config.url,
            status: response.status,
            data: response.data
        });
        return response;
    },
    (error) => {
        console.error('API Error Details:', {
            url: error.config?.url,
            method: error.config?.method,
            status: error.response?.status,
            statusText: error.response?.statusText,
            data: error.response?.data,
            headers: error.response?.headers
        });

        if (error.response?.status === 401) {
            console.log('Token expired or invalid, redirecting to login');
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            window.location.href = '/login';
        }

        return Promise.reject(error);
    }
);
export const authAPI = {
    register: (userData) => API.post('/auth/register', userData),
    login: (credentials) => API.post('/auth/login', credentials),
    getProfile: () => API.get('/auth/profile'),
    updateProfile: (profileData) => API.put('/auth/profile', profileData),
    checkAuth: () => API.get('/auth/check'),
};

export const activitiesAPI = {
    logActivity: (activityData) => API.post('/activities', activityData),
    getActivities: () => API.get('/activities'),
    deleteActivity: (id) => API.delete(`/activities/${id}`),
    getSummary: () => API.get('/activities/summary'),
};

export const goalsAPI = {
    setGoal: (goalData) => {
        console.log('Sending goal data:', goalData);  // Debug log
        return API.post('/goals', goalData);
    },
    getGoals: () => {
        console.log('Getting goals...');  // Debug log
        return API.get('/goals');
    },
    updateGoal: (id, goalData) => API.put(`/goals/${id}`, goalData),
    deleteGoal: (id) => API.delete(`/goals/${id}`),
};

export const statsAPI = {
    getStats: () => API.get('/stats'),
};
